// // This module implements a 8-bit register that stores the value of the input data on the negative edge of the clock signal only when the enable signal is low.
module reg_8bit(
    input clk,
    input en,
    input [7:0] d,
    output reg [7:0] q
);

always @(posedge clk) begin
    if (en) begin
        q <= d;
    end
end

endmodule
